mapper.select:
select usuario.usua_id,usua_login from administracion.usuario 
inner join administracion.dependencia_usuario on dependencia_usuario.usua_id=usuario.usua_id
where usuario.usua_id=#{usua_id}

select usuario.turn_id, usuario.usua_fecha_caducidad, usuario.usua_id,usuario.usua_login, usuario.grup_id, 
usuario.usua_estado, grupo.grup_nombre, grupo.grup_estado from administracion.usuario
inner join administracion.grupo on grupo.grup_id=usuario.grup_id where usuario.pers_id=#{id}

select t1.turn_id from administracion.usuario t1
inner join administracion.persona t2 on t1.pers_id = t2.pers_id
where t2.pers_dni = #{documento};

select usua_clave from administracion.usuario
where usua_login = #{usr}
limit 1 offset 0;

